//! Auto-generated by the spec-word-compliance workflow for area
//! **"Custom tab stops (tabs / CT_TabStop)"**.
//!
//! Each `#[test]` encodes a Word-consumption / serializer constraint mined from
//! ISO 29500-1/-4, ECMA-376, and the MS-OI29500 implementer notes for the
//! `w:tabs` / `w:tab` (CT_TabStop) markup. A FAILING assertion here is a real
//! Word-compliance gap in the stemma engine — stemma diverges from how a
//! conformant Word consumer reads or re-emits the markup. Do NOT weaken an
//! assertion to make it pass; a fail is the finding.
//!
//! Methodology note (consumption vs. save): stemma's serializer ACTIVELY
//! reconstructs `word/document.xml` paragraph properties from the typed IR (see
//! `serialize/mod.rs::build_paragraph_properties` — Position 10 `tabs`), so the
//! `xml*` expectations on the re-serialized body are valid for what the
//! serializer GENERATES (alignment token normalization, clear-filtering, pos
//! preservation, leader emission, child ordering). `opensClean` exercises the
//! package validator.

use std::io::{Read, Write};

use stemma::ExportOptions;
use stemma::api::Document;
use zip::write::FileOptions;

// ─── Prelude / plumbing ──────────────────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is the inner XML of `<w:body>`.
/// `extra_parts` is a list of `(part_name, xml)` to add to the archive (e.g.
/// `("word/styles.xml", ...)`); a Content-Types override is added for each.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-Types: defaults + document override + one override per extra part.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part_name, _) in extra_parts {
        let content_type = match *part_name {
            "word/styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "word/numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            other => panic!("make_docx: no Content-Type mapping for extra part {other}"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{part_name}" ContentType="{content_type}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    // document.xml.rels: one relationship per extra part (rId10+).
    let mut doc_rel_entries = String::new();
    for (i, (part_name, _)) in extra_parts.iter().enumerate() {
        let rel_type = match *part_name {
            "word/styles.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles"
            }
            "word/numbering.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering"
            }
            other => panic!("make_docx: no rel-type mapping for extra part {other}"),
        };
        let target = part_name.strip_prefix("word/").unwrap_or(part_name);
        doc_rel_entries.push_str(&format!(
            r#"<Relationship Id="rId{}" Type="{rel_type}" Target="{target}"/>"#,
            10 + i
        ));
    }
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rel_entries}</Relationships>"#
    );

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part_name, xml) in extra_parts {
            zip.start_file(*part_name, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx archive");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse the bytes, re-serialize via stemma's serializer, and return the
/// re-emitted `word/document.xml`. This is what the serializer GENERATES from
/// the typed IR (not a verbatim passthrough of the body).
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// Assert the package validator reports no errors (opens clean / no repair).
fn assert_opens_clean(bytes: &[u8], rule: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{rule} — expected the document to open clean (no repair), but the \
         validator reported issues: {:?}",
        report.issues
    );
}

// ─── Tests (one per TestSpec) ────────────────────────────────────────────────

#[test]
fn tab_val_bar_num_decimal_center_open_clean() {
    // ISO 29500-1 §17.18.84, §17.3.1.37
    let body = r#"<w:p><w:pPr><w:tabs><w:tab w:val="bar" w:pos="720"/><w:tab w:val="num" w:pos="1440"/><w:tab w:val="center" w:pos="2880"/><w:tab w:val="decimal" w:pos="4320"/></w:tabs></w:pPr><w:r><w:tab/><w:t>x</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.18.84/§17.3.1.37: bar, num, center, decimal are all \
         legal ST_TabJc enumeration values; a conformant consumer must open \
         the document without repair",
    );
}

#[test]
fn tab_leader_heavy_middledot_hyphen_underscore_open_clean() {
    // ISO 29500-1 §17.18.85, §17.3.1.37
    let body = r#"<w:p><w:pPr><w:tabs><w:tab w:val="start" w:pos="720" w:leader="heavy"/><w:tab w:val="start" w:pos="1440" w:leader="middleDot"/><w:tab w:val="start" w:pos="2880" w:leader="hyphen"/><w:tab w:val="start" w:pos="4320" w:leader="underscore"/></w:tabs></w:pPr><w:r><w:tab/><w:t>x</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.18.85/§17.3.1.37: heavy, middleDot, hyphen, underscore \
         are all legal ST_TabTlc leader values; a conformant consumer opens the \
         document without repair",
    );
}

#[test]
fn tab_pos_negative_permitted_open_clean() {
    // ISO 29500-1 §17.3.1.37, §17.18.81; MS-OI29500 §2.1.61
    let body = r#"<w:p><w:pPr><w:tabs><w:tab w:val="start" w:pos="-720"/><w:tab w:val="start" w:pos="1440"/></w:tabs></w:pPr><w:r><w:tab/><w:t>x</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.3.1.37 explicitly permits negative pos (moves the stop \
         into the margin); MS-OI29500 §2.1.61 places -720 inside Word's accepted \
         [-31680,31680] range, so the document opens without repair or clamping",
    );
}

#[test]
fn hanging_indent_with_tab_char_opens_clean() {
    // ISO 29500-1 §17.3.1.38, §17.3.1.12
    let body = r#"<w:p><w:pPr><w:ind w:left="720" w:hanging="360"/></w:pPr><w:r><w:t>1.</w:t></w:r><w:r><w:tab/></w:r><w:r><w:t>Body text aligned to the hanging stop.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.3.1.38: a hanging indent (§17.3.1.12 w:ind/@hanging) \
         implicitly creates the custom tab stop the leading tab lands on; the \
         construction is well-formed and Word opens it without repair",
    );
}

#[test]
fn tab_val_start_end_normalized_to_left_right_on_serialize() {
    // ISO 29500-1 §17.18.84, ECMA-376 §14.11.6, §17.3.1.37
    let body = r#"<w:p><w:pPr><w:tabs><w:tab w:val="start" w:pos="1440"/><w:tab w:val="end" w:pos="4320"/></w:tabs></w:pPr><w:r><w:t>A</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    // xmlRegex translated to contains: the serializer emits attributes in the
    // fixed order w:val then w:pos (serialize/mod.rs Position 10), so the
    // regex `<w:tab[^>]*w:val="(left|start)"[^>]*w:pos="1440"` reduces to a
    // contiguous-token contains check on the canonical emitted form. stemma
    // maps start->Left, so the canonical token is "left".
    let start_at_1440 = xml.contains(r#"w:val="left" w:pos="1440""#)
        || xml.contains(r#"w:val="start" w:pos="1440""#);
    assert!(
        start_at_1440,
        "ISO 29500-1 §17.18.84 / ECMA-376 §14.11.6: the 1440 stop carried \
         val='start' (leading edge); stemma maps start->Left and must emit the \
         left/leading token at pos=1440, never dropping the stop. Got: {xml}"
    );
    let end_at_4320 = xml.contains(r#"w:val="right" w:pos="4320""#)
        || xml.contains(r#"w:val="end" w:pos="4320""#);
    assert!(
        end_at_4320,
        "ISO 29500-1 §17.18.84 / ECMA-376 §14.11.6: the 4320 stop carried \
         val='end' (trailing edge); stemma maps end->Right and must emit the \
         right/trailing token at pos=4320. Got: {xml}"
    );
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.18.84: both start/end and the normalized left/right are \
         valid ST_TabJc values, so the document must open without repair",
    );
}

#[test]
fn bar_tab_stop_preserved_as_bar() {
    // ISO 29500-1 §17.18.84, §17.3.1.37
    let body = r#"<w:p><w:pPr><w:tabs><w:tab w:val="bar" w:pos="2160"/></w:tabs></w:pPr><w:r><w:t>C</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:val="bar""#),
        "ISO 29500-1 §17.18.84: bar is a distinct ST_TabJc value (draws a \
         vertical line); stemma's serializer must emit it as 'bar', not coerce \
         it to left/start. Got: {xml}"
    );
    assert!(
        xml.contains(r#"w:pos="2160""#),
        "ISO 29500-1 §17.3.1.37: the bar's position is preserved so the vertical \
         line is drawn at the original location. Got: {xml}"
    );
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.18.84: val='bar' is a valid ST_TabJc value; the \
         document must open without repair",
    );
}

#[test]
fn num_list_tab_legacy_value_opens_clean_and_preserved() {
    // ISO 29500-1 §17.18.84, §17.3.1.37
    let body = r#"<w:p><w:pPr><w:tabs><w:tab w:val="num" w:pos="720"/></w:tabs></w:pPr><w:r><w:t>D</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.18.84: num is a valid (if legacy) ST_TabJc enumeration \
         value; the document must open without repair",
    );
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:val="num""#),
        "ISO 29500-1 §17.18.84: stemma preserves the legacy list-tab value \
         through re-serialize rather than coercing it to left/start. Got: {xml}"
    );
    assert!(
        xml.contains(r#"w:pos="720""#),
        "ISO 29500-1 §17.3.1.37: the list-tab position is preserved. Got: {xml}"
    );
}

#[test]
fn decimal_tab_with_dot_leader_preserved() {
    // ISO 29500-1 §17.18.84, §17.18.85, §17.3.1.37
    let body = r#"<w:p><w:pPr><w:tabs><w:tab w:val="decimal" w:pos="5040" w:leader="dot"/></w:tabs></w:pPr><w:r><w:t>1.23</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    // xmlRegex `<w:tab[^>]*w:val="decimal"[^>]*w:pos="5040"` reduces (fixed
    // emit order val,pos,leader) to a contiguous-token contains check.
    assert!(
        xml.contains(r#"w:val="decimal" w:pos="5040""#),
        "ISO 29500-1 §17.18.84: decimal alignment is preserved so numeric text \
         aligns on the decimal point at 5040 twips. Got: {xml}"
    );
    assert!(
        xml.contains(r#"w:leader="dot""#),
        "ISO 29500-1 §17.18.85/§17.3.1.37: the dot leader is preserved on the \
         decimal stop; the leader is independent of alignment family. Got: {xml}"
    );
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.18.84/§17.18.85: decimal + dot leader is a valid \
         CT_TabStop; the document must open without repair",
    );
}

#[test]
fn negative_tab_pos_in_range_preserved() {
    // ISO 29500-1 §17.3.1.37, MS-OI29500 2.1.61
    let body = r#"<w:p><w:pPr><w:ind w:left="1440"/><w:tabs><w:tab w:val="left" w:pos="-720"/></w:tabs></w:pPr><w:r><w:t>E</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:pos="-720""#),
        "ISO 29500-1 §17.3.1.37 / MS-OI29500 2.1.61: a negative in-range \
         position is permitted (moves the stop into the margin); stemma \
         preserves it unchanged rather than clamping to 0. Got: {xml}"
    );
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.3.1.37 / MS-OI29500 2.1.61: pos=-720 is within Word's \
         permitted [-31680,31680] range, so the document must open without repair",
    );
}

#[test]
fn transitional_tab_val_left_right_aliases_open_clean() {
    // ISO 29500-4 §14.11.6, MS-OI29500 §2.1.556, ISO 29500-1 §17.18.84
    let body = r#"<w:p><w:pPr><w:tabs><w:tab w:val="left" w:pos="2160"/><w:tab w:val="right" w:pos="5040"/></w:tabs></w:pPr><w:r><w:t>A</w:t><w:tab/><w:t>B</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ISO 29500-4 §14.11.6 admits left/right for transitional docs and \
         MS-OI29500 §2.1.556 says Word maps them to start/end; stemma must not \
         flag the document as invalid",
    );
}

